INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000000', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'text', '{"html":"<h3>What Leveling Is</h3><p><strong>Leveling</strong> is the process of determining differences in elevation between points on, above, or below the surface of the earth. Where distance and angle measurement fix a point''s <em>horizontal</em> position, leveling fixes its <em>vertical</em> position &mdash; its <strong>elevation</strong>, the vertical distance above or below a chosen reference surface (datum). Almost every surveying and engineering project depends on reliable elevations: setting grades for roads and pipelines, mapping topography, designing drainage, computing earthwork volumes, and establishing flood elevations all begin with a level circuit.</p><p>The instrument we call a <strong>level</strong> does one thing extraordinarily well: it provides a <strong>horizontal line of sight</strong>. When the line of sight is truly horizontal, the difference between two rod readings taken from that single setup equals the difference in elevation between the two points the rod was held on. From that single, simple idea &mdash; a horizontal line of sight and a graduated rod &mdash; the entire discipline of leveling is built.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000001', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'text', '{"html":"<h3>Level Surfaces, Level Lines, and the Vertical</h3><p>To level correctly you must keep five related terms straight:</p><ul><li>A <strong>level surface</strong> is a continuous surface that is everywhere perpendicular to the direction of gravity (the plumb line). It is an <em>equipotential</em> surface &mdash; still water at rest lies on one. Because it follows gravity around the planet, a level surface is <strong>curved</strong>, roughly following the earth''s shape.</li><li>A <strong>level line</strong> lies entirely within a level surface; it too is curved.</li><li>A <strong>horizontal line</strong> is a straight line <em>tangent</em> to the level surface at one point &mdash; the line of sight your level provides. Over short sights the horizontal line and the level line are nearly identical; over long sights they diverge (the basis of the curvature correction studied later).</li><li>The <strong>vertical</strong> is the direction of gravity (plumb) at a point, perpendicular to the level surface.</li><li><strong>Elevation</strong> is the vertical distance from the datum (a chosen level surface) up or down to the point.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000002', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'callout', '{"type":"info","text":"A horizontal line and a level line agree only at the instrument. Because the level line curves away (down) from the straight horizontal sight, a perfectly horizontal line of sight reads slightly HIGH on a distant rod. This is the source of the curvature-and-refraction correction covered in Lesson 4 and the datums lesson."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000003', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'text', '{"html":"<h3>The Height-of-Instrument (HI) Method</h3><p>The workhorse computation of differential leveling is the <strong>Height-of-Instrument (HI) method</strong>. The HI is the elevation of the instrument''s horizontal line of sight &mdash; <em>not</em> the height of the telescope above the ground, but the elevation of the line of sight above the datum.</p><p>The procedure has two repeating steps. First, set the level and take a <strong>backsight (BS)</strong>: a rod reading on a point whose elevation is already known (a benchmark or turning point). Adding that reading to the known elevation gives the HI, because the rod reading is how far the line of sight rises above that known point. Second, take a <strong>foresight (FS)</strong>: a rod reading on a new point whose elevation you want. Subtracting the foresight from the HI gives the new elevation, because the foresight is how far the line of sight rises above the new point.</p><p>Backsights are also called <strong>plus sights (+)</strong> because they are added to an elevation to get the HI; foresights are <strong>minus sights (-)</strong> because they are subtracted from the HI to get an elevation. Master these two equations and you can level anything.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000004', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'equation', '{"latex":"HI = Elev_{BM} + BS \\qquad Elev_{pt} = HI - FS","label":"Height-of-Instrument equations","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000005', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'table', '{"headers":["Term","Symbol","Meaning"],"rows":[["Backsight","BS (+)","Rod reading on a point of KNOWN elevation; added to elevation to get HI"],["Height of Instrument","HI","Elevation of the level''s horizontal line of sight"],["Foresight","FS (-)","Rod reading on a point of UNKNOWN elevation; subtracted from HI to get elevation"],["Benchmark","BM","Permanent point of known, fixed elevation"],["Turning Point","TP","Temporary point that receives an FS then a BS to advance the circuit"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'text', '{"html":"<h3>Instruments and Accessories</h3><p>A modern leveling outfit consists of a <strong>level</strong> (an automatic/self-leveling level with a compensator, a digital/electronic level reading a bar-coded rod, or a precise tilting level for high-order work), a sturdy <strong>tripod</strong>, and a graduated <strong>leveling rod</strong> (commonly graduated in feet and hundredths, or in meters). Accessories include a <strong>rod level</strong> (a bull''s-eye bubble that keeps the rod plumb), a <strong>turning-point pin or plate</strong> (a stable, well-defined point for TPs), and a field book or data collector for recording the BS/HI/FS sequence. The single most common avoidable error in leveling is a rod that is not held plumb &mdash; a leaning rod always reads too long.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000007', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The HI method - BS added to a known elevation gives the line-of-sight elevation (HI); FS subtracted from HI gives the new point''s elevation."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0001-0000-0000-000000000008', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'key_takeaways', '{"title":"Key Takeaways","items":["Leveling determines differences in elevation using a horizontal line of sight referenced to a level surface.","A level surface is curved (perpendicular to gravity); the line of sight is a straight horizontal tangent to it.","HI = known elevation + backsight; new elevation = HI - foresight.","Backsights (+) are read on known points; foresights (-) are read on points whose elevation is sought.","Keeping the rod plumb and the line of sight truly horizontal are the foundations of accurate leveling."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000000', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'text', '{"html":"<h3>Carrying an Elevation: The Level Circuit</h3><p><strong>Differential leveling</strong> determines the difference in elevation between two points by direct observation. When the two points are too far apart, too far apart in elevation, or obstructed so they cannot be seen from a single setup, the elevation is <strong>carried</strong> through a series of instrument setups connected by <strong>turning points</strong>. The whole chain &mdash; from the starting benchmark, through every setup and turning point, to the final point (and, for control work, back to a benchmark) &mdash; is the <strong>level circuit</strong> or <strong>level run</strong>.</p><p>At each setup the level is placed roughly midway between the previous point and the next. The surveyor reads a <strong>backsight</strong> on the previous point (known elevation), computes the HI, then reads a <strong>foresight</strong> on the next point and computes its elevation. That next point becomes a <strong>turning point (TP)</strong>: a stable, well-defined point that receives a foresight from one setup and then a backsight from the next, passing the elevation forward like a baton.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000001', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'text', '{"html":"<h3>Recording and Reducing Level Notes</h3><p>Level notes are kept in columns: <strong>Station / BS (+) / HI / FS (-) / Elevation</strong>. The reduction follows the HI method mechanically. Begin at the benchmark with its known elevation. Add the backsight to get the first HI. Subtract the foresight on the first turning point to get that TP''s elevation. Move the instrument forward, backsight the same TP to get a new HI, foresight the next TP, and so on. The starting benchmark''s elevation is given; every other elevation in the table is computed.</p><p>Discipline in note-keeping is essential: read and record the backsight before disturbing the setup, hold the rod plumb on a firm point, and never assume &mdash; always carry the actual recorded numbers through the arithmetic. A single transposed digit propagates through every elevation that follows it.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000002', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'table', '{"headers":["Station","BS (+)","HI","FS (-)","Elevation"],"rows":[["BM-A","4.32","104.32","","100.00"],["TP1","5.18","106.74","2.76","101.56"],["TP2","3.44","107.10","3.08","103.66"],["BM-B","","","6.55","100.55"],["Sums","12.94","","12.39",""]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000003', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'callout', '{"type":"success","text":"Arithmetic check for the table above: Sum BS - Sum FS = 12.94 - 12.39 = +0.55 ft, and final - starting elevation = 100.55 - 100.00 = +0.55 ft. They agree, so the note reduction is arithmetically correct (this checks the math, NOT field accuracy)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000004', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'equation', '{"latex":"\\sum BS - \\sum FS = Elev_{last} - Elev_{first}","label":"Differential leveling arithmetic check","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000005', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'text', '{"html":"<h3>Why Balance Backsight and Foresight Distances</h3><p>The most important field technique in differential leveling is keeping the <strong>backsight and foresight distances equal</strong> at each setup. Three systematic errors all depend on sight length: <strong>earth curvature</strong> (the level line curves away from the horizontal sight), <strong>atmospheric refraction</strong> (the line of sight bends), and <strong>collimation error</strong> (the line of sight is not perfectly horizontal because of imperfect instrument adjustment). Each of these makes a rod read incorrectly by an amount proportional to the sight distance.</p><p>When the backsight and foresight distances are equal, the <em>same</em> error appears in both readings and <strong>cancels in the difference</strong>, because each setup computes a difference (BS - FS). This is why a surveyor paces or otherwise balances sight lengths and avoids excessively long sights. Balanced sights are far more powerful than precise instrument adjustment for controlling these systematic errors.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'accordion', '{"sections":[{"title":"Worked example: carrying an elevation","content":"<p>BM-A elevation = 100.00 ft. Setup 1: BS on BM-A = 4.32, so HI = 100.00 + 4.32 = 104.32. FS on TP1 = 2.76, so Elev TP1 = 104.32 - 2.76 = 101.56. Setup 2: BS on TP1 = 5.18, HI = 101.56 + 5.18 = 106.74. FS on TP2 = 3.08, Elev TP2 = 106.74 - 3.08 = 103.66. Setup 3: BS on TP2 = 3.44, HI = 103.66 + 3.44 = 107.10. FS on BM-B = 6.55, Elev BM-B = 107.10 - 6.55 = 100.55 ft.</p>","open":false},{"title":"Open vs. closed level circuits","content":"<p>An <strong>open</strong> level run ends on a different point than it started; it has no independent check on field accuracy. A <strong>closed</strong> level circuit either loops back to its starting benchmark or ties to a second benchmark of known elevation, providing a misclosure that measures the quality of the work (covered in Lesson 6). Control leveling should always be closed.</p>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0002-0000-0000-000000000007', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'key_takeaways', '{"title":"Key Takeaways","items":["Differential leveling carries an elevation through setups linked by turning points (the level circuit).","Reduce notes with the HI method: HI = elevation + BS; next elevation = HI - FS.","Balance backsight and foresight distances to cancel curvature, refraction, and collimation error.","Apply the arithmetic check: sum BS - sum FS must equal final elevation - starting elevation."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000000', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'text', '{"html":"<h3>Profile Leveling</h3><p><strong>Profile leveling</strong> determines the elevation of the ground surface along a defined line &mdash; the centerline of a proposed road, pipeline, ditch, or channel. The result is a <strong>profile</strong>: a side-view plot of ground elevation against horizontal distance (stationing) that engineers use to set grades, design vertical curves, and balance cut and fill. Unlike pure differential leveling, whose only goal is to carry an accurate elevation from point to point, profile leveling collects <em>many</em> ground elevations along the way.</p><p>It does this with two kinds of foresight. <strong>Turning-point foresights</strong> advance the circuit and carry the elevation, exactly as in differential leveling, and must be taken on firm, recoverable points. <strong>Intermediate foresights (IFS)</strong> &mdash; also called ground shots or rod shots &mdash; are taken on the ground at each station (and at every break in slope) to record the profile. Intermediate sights do <em>not</em> change the HI and are not part of the elevation-carrying arithmetic; they are simply HI minus the rod reading at each station.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000001', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'equation', '{"latex":"Elev_{station} = HI - IFS","label":"Ground elevation from an intermediate foresight","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000002', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'callout', '{"type":"warning","text":"Read intermediate foresights only to the precision the job needs (often the nearest 0.1 ft for a ground profile), but read turning-point foresights and backsights to full precision (0.01 ft). The accuracy of the whole profile depends on the turning points, not the ground shots."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000003', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'text', '{"html":"<h3>Stationing</h3><p>Positions along a route are described by <strong>stationing</strong>. A full station is 100 ft, written with a plus sign separating hundreds of feet from the remainder: station <strong>0+00</strong> is the beginning, <strong>1+00</strong> is 100 ft along, and <strong>12+50</strong> is 1,250 ft along. (In metric practice a full station is commonly 1,000 m or 100 m.) Profile shots are taken at each full or half station and at every significant grade break &mdash; the top and bottom of a bank, the edge of a creek, a change in slope &mdash; so the plotted profile faithfully represents the real ground.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000004', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'table', '{"headers":["Station","BS (+)","HI","IFS","FS (-)","Elevation"],"rows":[["BM-1","3.20","203.20","","","200.00"],["0+00","","","5.1","","198.1"],["1+00","","","6.4","","196.8"],["2+00","","","7.9","","195.3"],["TP1","2.85","199.30","","6.75","196.45"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000005', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'text', '{"html":"<h3>Cross-Section Leveling</h3><p><strong>Cross-section leveling</strong> measures ground elevations along lines drawn <em>perpendicular</em> to the route centerline at each station, extending left and right far enough to cover the construction limits. Each cross-section is a transverse profile of the ground. When the existing-ground cross-sections are compared with the proposed design template (the finished roadway or channel shape), the difference in area at each station gives the cut or fill area; multiplying these end areas by the distance between stations and summing yields <strong>earthwork volumes</strong> (the average-end-area method, treated in the volumes module).</p><p>Cross-section shots are recorded as offsets from centerline (e.g., 25 ft Left, centerline, 25 ft Right) with the elevation at each offset. Together, profile and cross-section data form the complete existing-ground model an engineer needs to design a route and estimate quantities.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A profile (elevation vs. station) and a typical cross-section (elevation vs. offset) used together to design grade and compute earthwork."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0003-0000-0000-000000000007', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'key_takeaways', '{"title":"Key Takeaways","items":["Profile leveling records ground elevations along a centerline to plot a vertical profile for design.","Intermediate foresights take ground shots (Elev = HI - IFS) but do not advance the circuit; only turning points do.","Stationing (e.g., 12+50 = 1,250 ft) locates each shot along the route.","Cross-section leveling provides perpendicular ground profiles used with the average-end-area method to compute earthwork volumes."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000000', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'text', '{"html":"<h3>Leveling with a Total Station</h3><p><strong>Trigonometric leveling</strong> determines a difference in elevation indirectly, from a measured distance and a measured vertical angle, rather than from a horizontal line of sight. It is the natural way a <strong>total station</strong> measures elevations: it observes the slope distance to a prism and the angle of the line of sight, and computes the vertical component trigonometrically. Trig leveling is efficient over rough or steep terrain where running a level circuit would require many setups, and it is the basis of how total-station topographic shots return an elevation along with a position.</p><p>The geometry is a right triangle. The measured line to the target is the hypotenuse (the <strong>slope distance S</strong>) or, with the horizontal distance known, one leg. The vertical angle of the line of sight fixes how that line rises or falls. The vertical leg of the triangle is the <strong>difference in elevation</strong> between the instrument''s line of sight and the target.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000001', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'text', '{"html":"<h3>The Elevation-Difference Equations</h3><p>Surveyors express the line of sight either as a <strong>vertical angle</strong> (measured up or down from the horizontal, positive above) or as a <strong>zenith angle</strong> (measured from the vertical/straight up, so a horizontal sight is 90&deg;). Total stations typically report zenith angles.</p><ul><li>From a <strong>vertical angle</strong> and the horizontal distance: <em>delta-elev = horizontal distance x tan(vertical angle)</em>.</li><li>From a <strong>vertical angle</strong> and the slope distance S: <em>delta-elev = S x sin(vertical angle)</em>.</li><li>From a <strong>zenith angle</strong> z and the slope distance S: <em>delta-elev = S x cos(z)</em>.</li></ul><p>These are the same triangle written three ways. A positive result means the target line of sight is above the instrument''s horizontal; a negative result means below.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000002', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'equation', '{"latex":"\\Delta Elev = d \\cdot \\tan(\\alpha) = S \\sin(\\alpha) = S \\cos(z)","label":"Trigonometric leveling: elevation difference","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000003', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'text', '{"html":"<h3>From Line of Sight to Ground Elevation</h3><p>The trig formula gives the rise or fall between the <em>instrument''s trunnion axis</em> and the <em>target</em>, not between the ground points. To get the elevation of the ground at the target you must add the <strong>instrument height (HI)</strong> &mdash; the measured height of the instrument''s center above its ground point &mdash; and subtract the <strong>target (or reflector) height</strong> &mdash; how high the prism sits above its ground point:</p></p><p style=\"margin-top:0\"><em>Elev<sub>target ground</sub> = Elev<sub>instrument ground</sub> + HI + delta-elev - target height.</em></p><p>For example, if a total station occupies a point of elevation 500.00 ft with HI = 5.20 ft, measures a slope distance of 240.00 ft at a zenith angle of 84&deg;00'', and the prism height is 6.00 ft: delta-elev = 240.00 x cos(84&deg;) = 240.00 x 0.10453 = +25.09 ft, so the target ground elevation = 500.00 + 5.20 + 25.09 - 6.00 = 524.29 ft.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000004', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'callout', '{"type":"warning","text":"Over long sights, trigonometric leveling needs a combined curvature-and-refraction correction (about +0.574 K^2 ft for a one-way sight, with K in miles - see the datums lesson). The most effective remedy is RECIPROCAL observation: measure the vertical angle in both directions and average, which largely cancels curvature, refraction, and instrument-index error."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000005', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Trigonometric leveling geometry - the vertical leg (delta-elev) is found from the slope distance and the vertical or zenith angle, then adjusted by instrument and target heights."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0004-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'key_takeaways', '{"title":"Key Takeaways","items":["Trigonometric leveling computes elevation difference from a distance and a vertical/zenith angle.","delta-elev = d x tan(vertical angle) = S x sin(vertical angle) = S x cos(zenith angle).","Add the instrument height and subtract the target height to convert line-of-sight rise to a ground elevation.","Use curvature-and-refraction corrections and reciprocal observations for long sights."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000000', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'text', '{"html":"<h3>The Lines and Axes of a Level</h3><p>A level is built around several reference lines that must hold a specific geometric relationship for the instrument to give a true horizontal line of sight. The principal ones are the <strong>vertical axis</strong> (about which the instrument rotates), the <strong>line of sight</strong> (the optical axis of the telescope defined by the crosshairs), and the <strong>axis of the level</strong> &mdash; the line that is horizontal when the bubble is centered (in a tilting level) or the reference that the automatic <strong>compensator</strong> establishes (in an automatic level). The fundamental adjustment requirement is that <strong>the line of sight be horizontal when the instrument is leveled</strong> &mdash; equivalently, that the line of sight be parallel to the axis of the level.</p><p>When that relationship is satisfied the level is <em>in adjustment</em>. When it is not, the line of sight tilts slightly up or down even though the bubble is centered, and every rod reading is biased.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000001', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'text', '{"html":"<h3>Collimation Error</h3><p><strong>Collimation error</strong> (line-of-sight error) is the small angular departure of the line of sight from true horizontal when the instrument has been leveled. Because the error is angular, its effect on a rod reading is <em>proportional to the sight distance</em>: a line of sight that droops by a tiny angle reads a little low on a near rod and much lower on a far rod. This is a <strong>systematic</strong> error &mdash; it always acts in the same sense for a given instrument &mdash; which makes it both dangerous (it accumulates) and, fortunately, controllable.</p><p>The key insight is that collimation error behaves exactly like curvature and refraction: it depends on distance. So the same field discipline &mdash; <strong>balancing backsight and foresight distances</strong> &mdash; causes the collimation error to be identical in the BS and the FS at each setup, where it cancels in the difference. A surveyor who balances sights can run accurate levels with an instrument that is slightly out of adjustment.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000002', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'callout', '{"type":"info","text":"Adjustment reduces the error at its source; good field technique (balanced sights, reciprocal observations) cancels whatever error remains. Professionals rely on BOTH - they check adjustment periodically and balance sights every setup."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000003', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'text', '{"html":"<h3>The Two-Peg Test</h3><p>The <strong>two-peg test</strong> detects and quantifies collimation error. Drive two pegs (A and B) a known distance apart &mdash; commonly about 200 ft. <strong>Step 1 (balanced):</strong> set the level exactly midway between A and B and read the rod on each. Because the sights are equal, any collimation error is identical in both readings and cancels, so the <em>difference</em> of these two readings is the <strong>true</strong> elevation difference between A and B. <strong>Step 2 (unbalanced):</strong> move the level close behind one peg (say a few feet behind A) and again read both rods. Now the sight to the far peg B is much longer than the sight to the near peg A, so collimation error inflates the far reading. Compare the elevation difference computed here against the true difference from Step 1; the discrepancy reveals the collimation error and lets you compute the correct reading the far rod <em>should</em> show, which is what you adjust the instrument to.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000004', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'equation', '{"latex":"\\Delta H_{true} = (a_1 - b_1)_{midpoint}, \\quad b_{2,correct} = a_2 - \\Delta H_{true}","label":"Two-peg test: true difference and corrected far reading","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000005', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'accordion', '{"sections":[{"title":"Two-peg test, worked numbers","content":"<p><strong>Midpoint:</strong> reading on A = 5.04, on B = 5.42, so true delta-H = 5.04 - 5.42 = -0.38 ft (B is lower). <strong>Near A:</strong> reading on A = 4.80; the correct far reading should be b = a - delta-H = 4.80 - (-0.38)... taking signs from the near setup, b should be 4.80 + 0.38 = 5.18 if A is higher. If the actual far reading is 5.23, the line of sight is high by 0.05 ft over that extra distance - the collimation error to remove by adjusting the crosshair (or to account for as a correction per 100 ft).</p>","open":false},{"title":"Other level adjustments","content":"<p>Besides collimation, a tilting level''s <strong>bubble (vial) adjustment</strong> keeps the bubble centered when the line of sight is horizontal; the <strong>crosshair adjustment</strong> keeps the horizontal hair truly horizontal. Automatic levels rely on a <strong>compensator</strong> whose proper function is verified by the two-peg test rather than a vial. Always confirm the compensator is working (lightly tap the instrument; the reading should return).</p>","open":false}]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0005-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'key_takeaways', '{"title":"Key Takeaways","items":["A level is in adjustment when the line of sight is horizontal (parallel to the level axis) once the instrument is leveled.","Collimation error tilts the line of sight; its effect on a rod reading grows with sight distance.","The two-peg test compares a balanced midpoint setup (true difference) with an unbalanced setup to quantify collimation error.","Balancing backsights and foresights cancels residual collimation error even when the instrument is slightly out of adjustment."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000000', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'text', '{"html":"<h3>Benchmarks and Vertical Control</h3><p>A <strong>benchmark (BM)</strong> is a permanent, recoverable physical point whose elevation has been established by leveling and is held fixed for future work &mdash; a brass disk set in concrete or bedrock, a bolt, or a stable monument. A connected collection of benchmarks forms a <strong>vertical-control network</strong>: the framework of known elevations to which all project leveling is tied. Just as horizontal control gives every survey a common positional reference, vertical control gives every elevation a common datum so that grades, floodplains, and as-builts from different crews and different years agree.</p><p>In the United States the national vertical-control network is maintained by the <strong>National Geodetic Survey (NGS)</strong>. Surveyors begin and end runs on published NGS or other reliable benchmarks; the published elevation, its datum, and its order/class of accuracy all matter and must be recorded.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000001', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'text', '{"html":"<h3>Vertical Datums: NAVD 88 and NGVD 29</h3><p>A <strong>vertical datum</strong> is the reference surface from which elevations are reckoned &mdash; conceptually a level surface near mean sea level (the geoid). Two datums dominate U.S. practice. The older <strong>National Geodetic Vertical Datum of 1929 (NGVD 29)</strong> was defined by holding mean sea level at 26 tide gauges. The current official datum is the <strong>North American Vertical Datum of 1988 (NAVD 88)</strong>, which is fixed to a single primary tidal benchmark (Father Point/Rimouski, Quebec) and a continent-wide releveling adjustment. <strong>Elevations are not the same in the two datums</strong> &mdash; the difference varies geographically (commonly a few tenths of a foot to over a foot across the conterminous U.S.). Always state which datum an elevation is on; mixing NAVD 88 and NGVD 29 values silently is a serious blunder.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000002', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'callout', '{"type":"warning","text":"Texas practice: published Texas elevations and most current projects use NAVD 88, but legacy plats, FEMA panels, and older record data may be on NGVD 29. Identify and record the datum (and the geoid model for GNSS-derived heights) on every project; never assume two elevation sources share a datum."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000003', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'text', '{"html":"<h3>Curvature and Refraction Correction</h3><p>Because the earth''s level surface curves away from a straight horizontal line of sight, a distant rod reads <strong>too high</strong> by the curvature amount; atmospheric <strong>refraction</strong> bends the line of sight back down and partially offsets curvature. The two are combined into a single correction that grows with the square of the sight distance. A convenient form for U.S. units is approximately <strong>0.574 K&sup2; feet, where K is the sight distance in miles</strong> (equivalently about 0.0206 K&sup2; ft for K in thousands of feet). For ordinary differential leveling the correction is made negligible simply by <strong>balancing backsight and foresight distances</strong>, but for long one-way trig-leveling sights it must be applied explicitly or removed by reciprocal observation.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000004', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'equation', '{"latex":"C_{cr} \\approx 0.574\\,K^{2}\\ \\text{ft} \\quad (K\\ \\text{in miles})","label":"Combined curvature-and-refraction correction","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000005', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'text', '{"html":"<h3>Loop Misclosure and Adjustment</h3><p>A <strong>closed level loop</strong> starts and ends on the same benchmark (or ties two benchmarks of known elevation). In a perfect loop the elevation you carry all the way around returns exactly to the starting value, so the <strong>misclosure</strong> &mdash; the difference between the computed and known elevation at the close &mdash; should be zero. In practice small random errors produce a nonzero misclosure. If it falls within the allowable tolerance for the order of work (a function of loop length), the loop is accepted and the misclosure is <strong>distributed</strong> back through the intermediate elevations to <strong>adjust (balance)</strong> the loop &mdash; commonly in proportion to the number of setups or the distance leveled to each point. The corrected elevations then sum consistently with the fixed benchmark(s).</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'equation', '{"latex":"Misclosure = Elev_{computed\\,at\\,close} - Elev_{known}","label":"Level-loop misclosure","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000007', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A closed level loop - misclosure at the return to the benchmark is distributed among the intermediate elevations to balance the loop."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0006-0000-0000-000000000008', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'key_takeaways', '{"title":"Key Takeaways","items":["A benchmark is a permanent point of known elevation; a network of them provides vertical control.","NAVD 88 is the current U.S. vertical datum (replacing NGVD 29); elevations differ between datums, so always record the datum.","Curvature and refraction make long sights read high; the combined correction is about 0.574 K^2 ft (K in miles).","A closed level loop''s misclosure (computed minus known at the close) is distributed to adjust the loop when within tolerance."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000000', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'text', '{"html":"<h3>Putting Leveling into Practice</h3><p>This lesson ties together the procedures from the module through worked field exercises. Real leveling work is judged not by a single reading but by whether a run <em>closes</em> &mdash; whether the elevations carried out into the field come back consistent with the control you started from. The professional habit to build is simple: reduce your notes and run your checks <strong>before you break down the instrument</strong>, so that if a run fails to close you can re-level it on the spot rather than returning another day.</p><p>Work each exercise below with disciplined note-keeping: record backsights and foresights to 0.01 ft, keep the rod plumb, choose firm turning points, and balance your sight distances. Then verify the arithmetic and assess the misclosure.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000001', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'text', '{"html":"<h3>Exercise 1 - Reduce a Differential Level Run</h3><p>Given BM-100 at elevation 250.00 ft, reduce the following run and find the elevation of BM-200.</p><p>Setup 1: BS on BM-100 = 6.41; FS on TP1 = 2.13. Setup 2: BS on TP1 = 5.87; FS on TP2 = 3.02. Setup 3: BS on TP2 = 4.55; FS on BM-200 = 7.96.</p><p><strong>Solution.</strong> HI&#8321; = 250.00 + 6.41 = 256.41; TP1 = 256.41 - 2.13 = 254.28. HI&#8322; = 254.28 + 5.87 = 260.15; TP2 = 260.15 - 3.02 = 257.13. HI&#8323; = 257.13 + 4.55 = 261.68; BM-200 = 261.68 - 7.96 = <strong>253.72 ft</strong>. <em>Check:</em> sum BS = 16.83, sum FS = 13.11; 16.83 - 13.11 = +3.72 = 253.72 - 250.00. The arithmetic checks.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000002', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'table', '{"headers":["Station","BS (+)","HI","FS (-)","Elevation"],"rows":[["BM-100","6.41","256.41","","250.00"],["TP1","5.87","260.15","2.13","254.28"],["TP2","4.55","261.68","3.02","257.13"],["BM-200","","","7.96","253.72"],["Sums","16.83","","13.11",""]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000003', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'text', '{"html":"<h3>Exercise 2 - Loop Misclosure</h3><p>A closed loop begins and ends on BM-A (elevation 412.500 ft). After running around the loop through several turning points, the computed elevation back at BM-A is 412.546 ft. The loop is 1.6 miles long.</p><p><strong>Solution.</strong> Misclosure = computed - known = 412.546 - 412.500 = <strong>+0.046 ft</strong>. A common allowable tolerance for ordinary leveling is on the order of 0.05 ft &times; sqrt(distance in miles) = 0.05 &times; sqrt(1.6) = 0.063 ft. Since 0.046 ft &lt; 0.063 ft, the loop is acceptable; the +0.046 ft is distributed (in proportion to setups or distance) back through the intermediate elevations to balance the loop.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000004', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'text', '{"html":"<h3>Exercise 3 - Trigonometric Leveling</h3><p>A total station at a point of elevation 600.00 ft (instrument height 5.30 ft) sights a prism (height 5.00 ft) on a hill. It measures a horizontal distance of 320.00 ft and a vertical angle of +6&deg;30'' above horizontal. Find the ground elevation at the prism.</p><p><strong>Solution.</strong> delta-elev = horizontal distance &times; tan(vertical angle) = 320.00 &times; tan(6.5&deg;) = 320.00 &times; 0.11394 = +36.46 ft. Ground elevation = 600.00 + 5.30 + 36.46 - 5.00 = <strong>636.76 ft</strong>. (Over this short sight the curvature-and-refraction correction, about 0.574 &times; (320/5280)&sup2; = 0.002 ft, is negligible.)</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000005', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'callout', '{"type":"success","text":"Field-check rule of thumb: never leave a control point until (1) the arithmetic check balances and (2) the loop misclosure is within tolerance for the order of work. A failed run found in the field costs an hour; one found in the office costs a day."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'accordion', '{"sections":[{"title":"Running a short level circuit, step by step","content":"<ol><li>Start on a known benchmark; record its elevation and datum.</li><li>Set the level roughly midway to the first turning point; verify it is level (compensator working).</li><li>Backsight the benchmark; compute HI = elevation + BS.</li><li>Foresight the turning point on a firm pin; compute elevation = HI - FS.</li><li>Advance the instrument, backsight the same TP, and repeat to the destination.</li><li>Close the run back on a benchmark; compute the misclosure and check it against tolerance; adjust if accepted.</li></ol>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0610-0007-0000-0000-000000000007', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'key_takeaways', '{"title":"Key Takeaways","items":["Reduce level notes with the HI method and confirm the arithmetic check before breaking down the instrument.","Compute loop misclosure (computed minus known at the close) and compare it to the allowable tolerance before accepting a run.","Trig leveling gives ground elevation from distance, vertical angle, instrument height, and target height.","Disciplined field habits - plumb rod, balanced sights, firm turning points, and immediate checks - prevent most leveling errors."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000001', 'Level surface', 'A continuous surface that is everywhere perpendicular to the direction of gravity; an equipotential surface that is curved, following the shape of the earth.', 'Still water at rest lies on one.', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000002', 'Height of Instrument (HI)', 'The elevation of the level''s horizontal line of sight above the datum, computed as HI = known elevation + backsight.', 'Not the height of the telescope above the ground.', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000003', 'Backsight (BS / plus sight)', 'A rod reading taken on a point of known elevation; it is added to that elevation to obtain the HI.', 'Always read FIRST from a setup, on a known point.', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000004', 'Foresight (FS / minus sight)', 'A rod reading taken on a point of unknown elevation; it is subtracted from the HI to obtain that point''s elevation.', NULL, 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000005', 'Turning point (TP)', 'A stable, well-defined temporary point that receives a foresight from one instrument setup and a backsight from the next, passing the elevation forward through a level circuit.', 'It gets both an FS and then a BS.', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000006', 'Balancing sight distances', 'Keeping the backsight and foresight distances equal at each setup so that curvature, refraction, and collimation errors are the same in both readings and cancel in the BS - FS difference.', NULL, 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000007', 'Level circuit (run)', 'The complete chain of instrument setups and turning points used to carry an elevation from a starting benchmark to other points and, ideally, back to a benchmark.', NULL, 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000008', 'Arithmetic check (differential leveling)', 'A check that the note reduction is correct: the sum of backsights minus the sum of foresights must equal the final elevation minus the starting elevation.', 'It checks the math, not the field accuracy.', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000009', 'Profile leveling', 'Leveling that determines ground elevations at regular stations along a defined line (centerline) to produce a vertical profile used for grade design.', 'Side-view of the ground along a route.', 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000010', 'Intermediate foresight (IFS)', 'A ground-elevation rod shot taken to record the profile; it equals HI minus the rod reading and does NOT advance the level circuit or change the HI.', NULL, 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000011', 'Stationing', 'A method of locating points along a route where a full station is 100 ft; e.g., station 12+50 is 1,250 ft from the beginning.', NULL, 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000012', 'Cross-section leveling', 'Leveling along lines perpendicular to the centerline at each station to capture the transverse ground profile, supplying end-area data for earthwork volume computation.', NULL, 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000013', 'Trigonometric leveling', 'Determining a difference in elevation indirectly from a measured slope (or horizontal) distance and a measured vertical/zenith angle, using right-triangle trigonometry.', 'How a total station gets elevations.', 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000014', 'Zenith angle', 'A vertical angle measured downward from the vertical (straight up); a horizontal line of sight reads 90 degrees. delta-elev = S x cos(zenith).', 'Total stations usually report this.', 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000015', 'Vertical angle', 'An angle measured up (+) or down (-) from the horizontal plane. With horizontal distance d: delta-elev = d x tan(vertical angle); with slope distance S: delta-elev = S x sin(vertical angle).', NULL, 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000016', 'Reciprocal observation (trig leveling)', 'Measuring the vertical angle in both directions between two points and averaging, which largely cancels curvature, refraction, and instrument index error over long sights.', NULL, 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000017', 'Collimation error', 'The angular departure of a level''s line of sight from true horizontal when the instrument is leveled; its effect on a rod reading is proportional to the sight distance.', 'A systematic, distance-dependent error.', 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000018', 'Two-peg test', 'A field procedure that quantifies collimation error by comparing the elevation difference between two pegs measured from a balanced midpoint setup (true) with that measured from an unbalanced setup near one peg.', NULL, 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000019', 'Line of sight (collimation axis)', 'The optical axis of a level''s telescope defined by the crosshairs; it must be horizontal when the instrument is leveled for the level to be in adjustment.', NULL, 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000020', 'Compensator', 'The gravity-actuated optical-mechanical device in an automatic level that automatically renders the line of sight horizontal; its function is verified with the two-peg test.', NULL, 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000021', 'Benchmark (BM)', 'A permanent, recoverable physical point of known, fixed elevation, used as a reference for leveling and held as part of the vertical-control network.', 'Brass disk in concrete or bedrock.', 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000022', 'NAVD 88', 'The North American Vertical Datum of 1988, the current official U.S. vertical datum, fixed to a primary tidal benchmark at Father Point/Rimouski; it replaced NGVD 29 and gives different elevations than NGVD 29.', NULL, 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000023', 'Curvature and refraction correction', 'A combined correction (about 0.574 K^2 ft with K in miles) accounting for the earth''s curvature making a long sight read high and atmospheric refraction partially offsetting it.', 'Eliminated by balancing sights or reciprocal observation.', 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000024', 'Level-loop misclosure', 'The difference between the computed elevation and the known elevation when a closed level loop returns to its starting (or a fixed) benchmark; ideally zero, and distributed to adjust the loop.', NULL, 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000025', 'Allowable misclosure', 'The maximum acceptable loop misclosure for a given order of leveling, commonly expressed as a constant times the square root of the loop length (e.g., 0.05 ft x sqrt(miles) for ordinary work).', 'It grows with loop length.', 'c1000006-0000-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000026', 'Field check (leveling)', 'Verifying, before leaving the field, that the arithmetic check balances and the loop misclosure is within tolerance, so any failed run can be re-leveled immediately.', NULL, 'c1000006-0000-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0640-0000-0000-0000-000000000027', 'Distributing misclosure', 'Adjusting (balancing) a closed level loop by spreading its misclosure back through the intermediate elevations in proportion to the number of setups or the distance leveled.', NULL, 'c1000006-0000-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', 'surveying', ARRAY['buildout','module-6']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000001', 'A level surface is best described as a surface that is:', 'multiple_choice', '["Perfectly flat and planar over any distance","Everywhere perpendicular to the direction of gravity (an equipotential surface)","Always parallel to the line of sight of the level","Tangent to the earth only at the equator"]'::jsonb, 'Everywhere perpendicular to the direction of gravity (an equipotential surface)', 'A level surface is equipotential and everywhere perpendicular to gravity, so it is curved (still water lies on one). A flat plane is a horizontal surface, which is only tangent to the level surface at one point.', 'easy', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000002', 'A benchmark has an elevation of 245.60 ft. A backsight of 4.85 ft is read on it. What is the height of instrument (HI)?', 'multiple_choice', '["240.75 ft","250.45 ft","245.60 ft","4.85 ft"]'::jsonb, '250.45 ft', 'HI = benchmark elevation + backsight = 245.60 + 4.85 = 250.45 ft. The backsight is added to a known elevation to obtain the line-of-sight elevation.', 'easy', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000003', 'A backsight is always taken on a point of known elevation, while a foresight is taken on a point whose elevation is being determined.', 'true_false', '["True","False"]'::jsonb, 'True', 'By definition a backsight (plus sight) is read on a point of known elevation and added to it to get the HI; a foresight (minus sight) is read on a new point and subtracted from the HI to get its elevation.', 'easy', 'c1000006-0000-0000-0000-000000000006', '757aea26-6c36-463a-9fa7-67243b0cdf5b', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000004', 'The HI at a setup is 308.20 ft. A foresight of 6.14 ft is read on a turning point. What is the elevation of the turning point?', 'multiple_choice', '["314.34 ft","302.06 ft","308.20 ft","6.14 ft"]'::jsonb, '302.06 ft', 'Elevation = HI - FS = 308.20 - 6.14 = 302.06 ft. Foresights are subtracted from the HI to obtain a point''s elevation.', 'easy', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000005', 'Why do surveyors keep backsight and foresight distances equal at each setup?', 'multiple_choice', '["To make the rod easier to read at a constant focus","So that curvature, refraction, and collimation errors are equal in both readings and cancel in the BS - FS difference","To reduce the number of turning points required","Because the instrument cannot focus on unequal distances"]'::jsonb, 'So that curvature, refraction, and collimation errors are equal in both readings and cancel in the BS - FS difference', 'These three errors are all proportional to sight distance. Equal BS and FS distances make the error identical in each reading, so it cancels when the difference is taken.', 'medium', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000006', 'In a set of level notes the sum of the backsights is 18.40 ft and the sum of the foresights is 15.10 ft. The starting elevation was 500.00 ft. What must the final elevation be for the arithmetic check to pass?', 'multiple_choice', '["496.70 ft","503.30 ft","533.50 ft","500.00 ft"]'::jsonb, '503.30 ft', 'Sum BS - sum FS = 18.40 - 15.10 = +3.30 ft, which must equal final - starting elevation, so final = 500.00 + 3.30 = 503.30 ft.', 'medium', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000007', 'The arithmetic check (sum BS - sum FS = last elevation - first elevation) proves that the field measurements are accurate.', 'true_false', '["True","False"]'::jsonb, 'False', 'The arithmetic check only verifies that the note reduction (the math) is correct. Field accuracy is judged by closing the loop and checking the misclosure against tolerance.', 'medium', 'c1000006-0000-0000-0000-000000000006', '26c31d15-d0aa-495a-b954-79e07133f0d2', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000008', 'In profile leveling, an intermediate foresight (IFS) differs from a turning-point foresight because the intermediate foresight:', 'multiple_choice', '["Changes the height of instrument","Records a ground elevation but does not advance the level circuit","Must be read more precisely than the backsight","Can only be taken on a benchmark"]'::jsonb, 'Records a ground elevation but does not advance the level circuit', 'An intermediate foresight gives a ground shot (Elev = HI - IFS) without changing the HI or carrying the elevation forward. Only turning points advance the circuit.', 'medium', 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000009', 'How many feet from the beginning of a route is station 14+25?', 'multiple_choice', '["1,425 ft","142.5 ft","1,400 ft","14.25 ft"]'::jsonb, '1,425 ft', 'A full station is 100 ft, so 14+25 means 14 x 100 + 25 = 1,425 ft from the beginning of the route.', 'easy', 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000010', 'What is the primary purpose of cross-section leveling?', 'multiple_choice', '["To establish a network of permanent benchmarks","To capture ground elevations perpendicular to the centerline so earthwork (cut/fill) volumes can be computed","To check the collimation of the level","To measure horizontal angles along a route"]'::jsonb, 'To capture ground elevations perpendicular to the centerline so earthwork (cut/fill) volumes can be computed', 'Cross-sections give the transverse ground profile at each station; compared with the design template they yield end areas used (via average-end-area) to compute earthwork volumes.', 'medium', 'c1000006-0000-0000-0000-000000000006', '23b640e3-b819-4f1b-88de-49b8fb3003be', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000011', 'Using a zenith angle z and a slope distance S, the difference in elevation between the instrument line of sight and the target is:', 'multiple_choice', '["S x sin(z)","S x cos(z)","S x tan(z)","S / cos(z)"]'::jsonb, 'S x cos(z)', 'The zenith angle is measured from the vertical, so the vertical component of the slope distance is S x cos(z). (With a vertical angle from horizontal it would be S x sin or d x tan.)', 'medium', 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000012', 'A total station measures a horizontal distance of 150.00 ft and a vertical angle of +4°00'' above horizontal. What is the difference in elevation (rise) of the line of sight, to the nearest 0.01 ft?', 'numeric_input', '[]'::jsonb, '10.49', 'delta-elev = horizontal distance x tan(vertical angle) = 150.00 x tan(4°) = 150.00 x 0.06993 = 10.49 ft.', 'medium', 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000013', 'To convert the line-of-sight elevation difference from trigonometric leveling into the target''s ground elevation, you should:', 'multiple_choice', '["Add the target height and subtract the instrument height","Add the instrument height (HI) and subtract the target (reflector) height","Subtract both the instrument and target heights","Ignore instrument and target heights for short sights"]'::jsonb, 'Add the instrument height (HI) and subtract the target (reflector) height', 'Ground elevation = instrument-ground elevation + HI + delta-elev - target height. The trig delta-elev is between the trunnion axis and the prism, so you add the instrument height and subtract the prism height.', 'hard', 'c1000006-0000-0000-0000-000000000006', 'fd4b3508-a1ac-46ec-9210-632757407f8e', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000014', 'Collimation (line-of-sight) error in a level:', 'multiple_choice', '["Has the same effect on every rod reading regardless of distance","Is random and averages out automatically","Produces a reading error proportional to the sight distance","Only occurs with digital levels"]'::jsonb, 'Produces a reading error proportional to the sight distance', 'Collimation error is an angular tilt of the line of sight, so its effect on a rod reading grows with distance. This is why balancing BS and FS distances cancels it.', 'medium', 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000015', 'In the two-peg test, why is the elevation difference obtained from the midpoint (balanced) setup taken as the TRUE difference?', 'multiple_choice', '["Because the instrument is closer to both pegs","Because equal sight distances make collimation error identical in both readings, so it cancels in the difference","Because refraction does not act at the midpoint","Because the rod is read only once"]'::jsonb, 'Because equal sight distances make collimation error identical in both readings, so it cancels in the difference', 'At the midpoint the backsight and foresight distances are equal, so any collimation error appears equally in both readings and cancels when their difference is taken, giving the true elevation difference.', 'hard', 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000016', 'Balancing backsight and foresight distances can compensate for an instrument that is slightly out of collimation adjustment.', 'true_false', '["True","False"]'::jsonb, 'True', 'Because collimation error is proportional to distance, equal BS and FS distances make the error cancel in the difference, so accurate levels can be run even with a slightly maladjusted instrument.', 'medium', 'c1000006-0000-0000-0000-000000000006', '0ca1c9a9-5739-4c26-9694-9c93de7311ef', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000017', 'Which statement about NAVD 88 and NGVD 29 is correct?', 'multiple_choice', '["They are identical and the names are interchangeable","NAVD 88 is the current official U.S. vertical datum and gives different elevations than NGVD 29","NGVD 29 replaced NAVD 88 in 1988","Both are horizontal datums, not vertical datums"]'::jsonb, 'NAVD 88 is the current official U.S. vertical datum and gives different elevations than NGVD 29', 'NAVD 88 replaced NGVD 29 as the official vertical datum; elevations differ between them (varying geographically), so the datum must always be recorded.', 'medium', 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000018', 'A closed level loop starts and ends on BM-7 (elevation 318.200 ft) but the computed elevation on returning is 318.235 ft. What is the misclosure?', 'multiple_choice', '["+0.035 ft","-0.035 ft","+0.235 ft","0.000 ft"]'::jsonb, '+0.035 ft', 'Misclosure = computed at close - known = 318.235 - 318.200 = +0.035 ft. If within tolerance it is distributed back through the intermediate elevations to balance the loop.', 'medium', 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000019', 'Over a one-way sight of 0.50 mile, what is the approximate combined curvature-and-refraction correction using C = 0.574 K^2 ft (K in miles)?', 'numeric_input', '[]'::jsonb, '0.14', 'C = 0.574 x (0.50)^2 = 0.574 x 0.25 = 0.1435, about 0.14 ft. The correction grows with the square of the sight distance.', 'hard', 'c1000006-0000-0000-0000-000000000006', '1e3bdc32-d674-4349-908e-41b96cf04b04', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000020', 'BM-1 has elevation 100.00 ft. A backsight of 5.50 ft is read on it; a foresight of 3.20 ft is read on point P from the same setup. What is the elevation of P?', 'multiple_choice', '["102.30 ft","97.70 ft","108.70 ft","105.50 ft"]'::jsonb, '102.30 ft', 'HI = 100.00 + 5.50 = 105.50 ft; Elev P = HI - FS = 105.50 - 3.20 = 102.30 ft.', 'easy', 'c1000006-0000-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0630-0000-0000-0000-000000000021', 'Before breaking down the instrument at the end of a control level run, a surveyor should at minimum confirm that:', 'multiple_choice', '["The weather forecast is clear","The arithmetic check balances and the loop misclosure is within tolerance","The benchmark disk is newly painted","Only the final foresight was recorded"]'::jsonb, 'The arithmetic check balances and the loop misclosure is within tolerance', 'Checking the arithmetic and the misclosure in the field lets a failed run be re-leveled immediately, which is far cheaper than discovering the failure in the office.', 'easy', 'c1000006-0000-0000-0000-000000000006', '911b6af8-808a-4c04-9bd2-7deffb3be294', ARRAY['buildout','module-6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0660-0000-0000-0000-000000000001', 'A benchmark has a known elevation of {{bm:f2}} ft. From an instrument setup, a backsight of {{bs:f2}} ft is read on the benchmark. Compute the Height of Instrument (HI), in feet.', 'numeric_input', '[]'::jsonb, '0', 'The backsight is added to the known benchmark elevation: HI = {{bm:f2}} + {{bs:f2}} = {{_answer}} ft. The HI is the elevation of the level''s horizontal line of sight.', 'easy', 'c1000006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-6','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0650-0000-0000-0000-000000000001', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0660-0000-0000-0000-000000000002', 'The Height of Instrument at a setup is {{hi:f2}} ft. A foresight of {{fs:f2}} ft is read on a new point. Compute the elevation of that point, in feet.', 'numeric_input', '[]'::jsonb, '0', 'The foresight is subtracted from the HI to get the new point''s elevation: Elev = {{hi:f2}} - {{fs:f2}} = {{_answer}} ft.', 'easy', 'c1000006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-6','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0650-0000-0000-0000-000000000002', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0660-0000-0000-0000-000000000003', 'A total station measures a horizontal distance of {{dist:f2}} ft to a target and a vertical angle of {{vang:f2}} degrees above the horizontal. Compute the difference in elevation (rise of the line of sight to the target), in feet.', 'numeric_input', '[]'::jsonb, '0', 'delta-elev = horizontal distance x tan(vertical angle) = {{dist:f2}} x tan({{vang:f2}}°) = {{dist:f2}} x {{tanv:f4}} = {{_answer}} ft.', 'medium', 'c1000006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-6','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0650-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0660-0000-0000-0000-000000000004', 'A closed level loop returns to its starting benchmark. The sum of all backsights is {{sumbs:f3}} ft and the sum of all foresights is {{sumfs:f3}} ft. For a perfectly closed loop these should be equal. Compute the loop misclosure (sum BS - sum FS), in feet.', 'numeric_input', '[]'::jsonb, '0', 'Around a closed loop the carried elevation should return to its start, so sum BS should equal sum FS. The misclosure is sum BS - sum FS = {{sumbs:f3}} - {{sumfs:f3}} = {{_answer}} ft, which (if within tolerance) is distributed to balance the loop.', 'medium', 'c1000006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-6','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0650-0000-0000-0000-000000000004', 0.002);
