UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Leveling determines differences in elevation by referencing a horizontal line of sight to a level surface.','A level surface is curved (follows gravity); a horizontal line is the straight tangent to it at the instrument.','The Height-of-Instrument method drives all differential leveling: HI = known elevation + backsight; new elevation = HI - foresight.','A backsight (BS or +) is read on a point of known elevation; a foresight (FS or -) is read on a point whose elevation is being determined.']::text[], learning_objectives=ARRAY['Define leveling and explain how a level establishes a horizontal line of sight referenced to a level (equipotential) surface.','Distinguish among a level surface, a level line, a horizontal line, the vertical, and elevation.','State and apply the Height-of-Instrument (HI) method, including HI = BM elevation + BS and elevation = HI - FS.','Identify the major instruments and accessories used in differential leveling and what each contributes.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='757aea26-6c36-463a-9fa7-67243b0cdf5b';
DELETE FROM lesson_blocks WHERE lesson_id='757aea26-6c36-463a-9fa7-67243b0cdf5b';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Differential leveling carries an elevation from a benchmark to other points through a chain of setups linked by turning points.','At each setup: HI = previous elevation + BS, then elevation of the next point = HI - FS.','Balancing backsight and foresight distances cancels curvature, refraction, and most collimation error.','Arithmetic check: (sum of backsights) - (sum of foresights) = (final elevation) - (starting elevation).']::text[], learning_objectives=ARRAY['Carry an elevation from a benchmark to a distant point through a series of instrument setups and turning points (the level circuit).','Record and reduce level notes using the HI method, computing HI and elevations at each setup.','Use turning points correctly and explain why balanced backsight and foresight distances eliminate systematic errors.','Apply the arithmetic check (sum BS - sum FS = last elevation - first elevation) to a set of level notes.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='26c31d15-d0aa-495a-b954-79e07133f0d2';
DELETE FROM lesson_blocks WHERE lesson_id='26c31d15-d0aa-495a-b954-79e07133f0d2';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Profile leveling records ground elevations at regular stations along a route to plot a vertical profile.','Intermediate foresights (IFS) take ground-elevation shots but do not advance the circuit; only turning points do.','Cross-section leveling measures ground elevations perpendicular to the centerline at each station for earthwork volumes.','Stationing (e.g., 12+50 = 1250 ft) locates each shot along the route.']::text[], learning_objectives=ARRAY['Explain the purpose of profile leveling and how intermediate foresights produce a continuous ground profile along a line.','Distinguish intermediate sights (used for ground shots) from turning-point foresights (used to advance the circuit).','Describe cross-section leveling and how it supplies the data needed to compute earthwork volumes.','Read and interpret stationing, a profile plot, and a typical cross-section.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='23b640e3-b819-4f1b-88de-49b8fb3003be';
DELETE FROM lesson_blocks WHERE lesson_id='23b640e3-b819-4f1b-88de-49b8fb3003be';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Trigonometric leveling derives elevation difference from a distance and a vertical (or zenith) angle, not a level line of sight.','With a vertical angle a above horizontal: delta-elev = (horizontal distance) x tan(a); with a slope distance S: delta-elev = S x sin(a).','With a zenith angle z (from straight up): delta-elev = S x cos(z).','Full elevation = instrument elevation + instrument height + delta-elev - target height (plus curvature/refraction over long sights).']::text[], learning_objectives=ARRAY['Explain how trigonometric leveling obtains a difference in elevation from a measured slope distance (or horizontal distance) and a vertical/zenith angle.','Apply the elevation-difference equations using either a vertical angle (dist x tan) or a zenith angle (S x cos zenith).','Compute a point''s elevation accounting for instrument height (HI) and reflector/target height.','Recognize when curvature-and-refraction corrections and reciprocal observations are needed.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='fd4b3508-a1ac-46ec-9210-632757407f8e';
DELETE FROM lesson_blocks WHERE lesson_id='fd4b3508-a1ac-46ec-9210-632757407f8e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['A level is in adjustment when the line of sight is parallel to the axis of the level (bubble/compensator), so it is horizontal when the instrument is level.','Collimation error is a line of sight that is not truly horizontal when the instrument is leveled; it grows with sight distance.','The two-peg test isolates collimation error by comparing readings from a balanced midpoint setup with readings from an unbalanced setup.','Balancing backsight and foresight distances cancels collimation error even if the instrument is slightly out of adjustment.']::text[], learning_objectives=ARRAY['Identify the principal lines and axes of a level and state the desired geometric relationships among them.','Define collimation (line-of-sight) error and explain its effect on rod readings.','Perform the two-peg test to detect and quantify collimation error, and compute the collimation correction.','Explain why reciprocal leveling and balanced sights protect a level run from residual instrument error.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='0ca1c9a9-5739-4c26-9694-9c93de7311ef';
DELETE FROM lesson_blocks WHERE lesson_id='0ca1c9a9-5739-4c26-9694-9c93de7311ef';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A benchmark is a permanent point of known elevation; a connected set forms the vertical-control network on which projects depend.','NAVD 88 is the current official vertical datum for the United States, replacing NGVD 29; elevations differ between them.','Curvature and refraction make a long horizontal sight read high; the combined correction is about 0.574 K^2 ft with K in miles.','A closed level loop should return to its start with zero misclosure; the actual misclosure is distributed to adjust the loop.']::text[], learning_objectives=ARRAY['Define a benchmark and a vertical datum and explain the role of a benchmark network in vertical control.','Describe the modern North American vertical datum NAVD 88 and contrast it with the older NGVD 29.','Apply the combined curvature-and-refraction correction to long level or trig-leveling sights.','Compute the misclosure of a closed level loop and distribute the correction to balance (adjust) the loop.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='1e3bdc32-d674-4349-908e-41b96cf04b04';
DELETE FROM lesson_blocks WHERE lesson_id='1e3bdc32-d674-4349-908e-41b96cf04b04';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Always reduce notes with the HI method and confirm the arithmetic check before leaving the field.','Close every control loop and compare its misclosure to the allowable tolerance for the order of work.','Trig leveling and differential leveling can be combined on the same project; track instrument and target heights carefully.','Good field habits - plumb rod, balanced sights, firm turning points, and immediate checks - prevent most leveling errors.']::text[], learning_objectives=ARRAY['Reduce a complete set of differential-level field notes, computing HI and every elevation and applying the arithmetic check.','Compute the misclosure of a closed level loop and judge it against an allowable tolerance.','Apply trigonometric leveling to find a point''s elevation from field measurements.','Set up, run, and check a short level circuit following correct field procedure.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='911b6af8-808a-4c04-9bd2-7deffb3be294';
DELETE FROM lesson_blocks WHERE lesson_id='911b6af8-808a-4c04-9bd2-7deffb3be294';
  'eeee0650-0000-0000-0000-000000000001', 'Height of Instrument from a benchmark', 'Height of Instrument from a benchmark', 'Leveling and Vertical Control — Differential Leveling', 'Height of Instrument', 'numeric_input', 'easy', 'A benchmark has a known elevation of {{bm:f2}} ft. From an instrument setup, a backsight of {{bs:f2}} ft is read on the benchmark. Compute the Height of Instrument (HI), in feet.', 'bm + bs', '{"decimals":2,"unit":"ft","tolerance":0.01}', '[{"name":"bm","type":"float","min":100,"max":900,"decimals":2},{"name":"bs","type":"float","min":1.5,"max":11.5,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Add the backsight to the benchmark elevation","formula":"HI = BM + BS","calculation_template":"{{bm:f2}} + {{bs:f2}}"},{"step_number":2,"title":"Height of Instrument","result_template":"HI = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The backsight is added to the known benchmark elevation: HI = {{bm:f2}} + {{bs:f2}} = {{_answer}} ft. The HI is the elevation of the level''s horizontal line of sight.', 'c1000006-0000-0000-0000-000000000006', ARRAY['buildout','module-6','practice']::text[], true, 'buildout:m6');
  'eeee0650-0000-0000-0000-000000000002', 'Elevation of a point from HI and foresight', 'Elevation of a point from HI and foresight', 'Leveling and Vertical Control — Differential Leveling', 'Elevation from foresight', 'numeric_input', 'easy', 'The Height of Instrument at a setup is {{hi:f2}} ft. A foresight of {{fs:f2}} ft is read on a new point. Compute the elevation of that point, in feet.', 'hi - fs', '{"decimals":2,"unit":"ft","tolerance":0.01}', '[{"name":"hi","type":"float","min":110,"max":910,"decimals":2},{"name":"fs","type":"float","min":1,"max":11.5,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Subtract the foresight from the HI","formula":"Elev = HI - FS","calculation_template":"{{hi:f2}} - {{fs:f2}}"},{"step_number":2,"title":"Point elevation","result_template":"Elev = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The foresight is subtracted from the HI to get the new point''s elevation: Elev = {{hi:f2}} - {{fs:f2}} = {{_answer}} ft.', 'c1000006-0000-0000-0000-000000000006', ARRAY['buildout','module-6','practice']::text[], true, 'buildout:m6');
  'eeee0650-0000-0000-0000-000000000003', 'Trigonometric leveling elevation difference', 'Trigonometric leveling elevation difference', 'Leveling and Vertical Control — Trigonometric Leveling', 'Elevation difference from vertical angle', 'numeric_input', 'medium', 'A total station measures a horizontal distance of {{dist:f2}} ft to a target and a vertical angle of {{vang:f2}} degrees above the horizontal. Compute the difference in elevation (rise of the line of sight to the target), in feet.', 'dist*tan(toRad(vang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"dist","type":"float","min":100,"max":500,"decimals":2},{"name":"vang","type":"float","min":2,"max":15,"decimals":2}]'::jsonb, '[{"name":"tanv","formula":"tan(toRad(vang))"}]'::jsonb, '[{"step_number":1,"title":"Tangent of the vertical angle","formula":"tan(vertical angle)","calculation_template":"tan({{vang:f2}}°) = {{tanv:f4}}"},{"step_number":2,"title":"Elevation difference","formula":"delta-elev = dist x tan(vertical angle)","result_template":"{{dist:f2}} x {{tanv:f4}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'delta-elev = horizontal distance x tan(vertical angle) = {{dist:f2}} x tan({{vang:f2}}°) = {{dist:f2}} x {{tanv:f4}} = {{_answer}} ft.', 'c1000006-0000-0000-0000-000000000006', ARRAY['buildout','module-6','practice']::text[], true, 'buildout:m6');
  'eeee0650-0000-0000-0000-000000000004', 'Level-loop misclosure from sum BS and sum FS', 'Level-loop misclosure from sum BS and sum FS', 'Leveling and Vertical Control — Adjustment', 'Loop misclosure', 'numeric_input', 'medium', 'A closed level loop returns to its starting benchmark. The sum of all backsights is {{sumbs:f3}} ft and the sum of all foresights is {{sumfs:f3}} ft. For a perfectly closed loop these should be equal. Compute the loop misclosure (sum BS - sum FS), in feet.', 'sumbs - sumfs', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumbs","type":"float","min":20,"max":40,"decimals":3},{"name":"err","type":"float","min":-0.06,"max":0.06,"decimals":3}]'::jsonb, '[{"name":"sumfs","formula":"sumbs - err"}]'::jsonb, '[{"step_number":1,"title":"Difference of the sums","formula":"misclosure = sum BS - sum FS","calculation_template":"{{sumbs:f3}} - {{sumfs:f3}}"},{"step_number":2,"title":"Loop misclosure","result_template":"misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Around a closed loop the carried elevation should return to its start, so sum BS should equal sum FS. The misclosure is sum BS - sum FS = {{sumbs:f3}} - {{sumfs:f3}} = {{_answer}} ft, which (if within tolerance) is distributed to balance the loop.', 'c1000006-0000-0000-0000-000000000006', ARRAY['buildout','module-6','practice']::text[], true, 'buildout:m6');
COMMIT;
SELECT 'm6 Leveling and Vertical Control: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000006-0000-0000-0000-000000000006') || ' blocks.' AS status;